	data, err := os.ReadFile(filepath.Join(wsRoot, "myrepo", ".env"))
	if err != nil {
		t.Fatalf(".env not written on fresh clone: %v", err)
	}
	if !strings.Contains(string(data), "API_KEY=fresh") {
		t.Errorf(".env missing API_KEY; contents:\n%s", data)
	}
}
